import{_ as o,o as a,c as e,a2 as r}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"中和殿","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/forbidden-city/zhonghe-dian.md","filePath":"landmarks/forbidden-city/zhonghe-dian.md","lastUpdated":1784720050000}'),n={name:"landmarks/forbidden-city/zhonghe-dian.md"};function l(s,t,i,d,u,g){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="中和殿" tabindex="-1">中和殿 <a class="header-anchor" href="#中和殿" aria-label="Permalink to &quot;中和殿&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1590829495436-6231c80f6a6a?w=1200&amp;q=80" alt="中和殿"></p><blockquote><p>三殿之中，方亭独立。它是大典前的一息静默，也是&quot;中庸&quot;之道在建筑上的化身。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>中和殿是外朝三大殿的中间一座，位于太和殿与保和殿之间，建成于明永乐十八年（1420年），初名&quot;华盖殿&quot;，嘉靖年间改名&quot;中极殿&quot;，清顺治二年（1645年）定名&quot;中和殿&quot;。其名取自《礼记·中庸》&quot;喜怒哀乐之未发谓之中，发而皆中节谓之和&quot;，寓意帝王行事当持守中正、致达和谐。</p><p>在三大殿的序列中，中和殿体量最小，形制却最独特：它是三殿中唯一的<strong>方形攒尖顶</strong>建筑，外观玲珑如亭，与前后两座恢宏的长方形大殿形成鲜明的节奏对比。这座小殿并非摆设——它是皇帝赴太和殿举行大典前的休憩之所，也是国家农事与祭祀礼仪的准备空间。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>平面形制</strong></td><td style="text-align:left;">正方形，面阔、进深各三间</td></tr><tr><td style="text-align:left;"><strong>屋顶</strong></td><td style="text-align:left;">单檐四角攒尖顶，鎏金宝顶</td></tr><tr><td style="text-align:left;"><strong>建筑面积</strong></td><td style="text-align:left;">约580平方米</td></tr><tr><td style="text-align:left;"><strong>殿内匾额</strong></td><td style="text-align:left;">&quot;允执厥中&quot;（乾隆御笔）</td></tr><tr><td style="text-align:left;"><strong>殿内陈设</strong></td><td style="text-align:left;">两座肩舆（皇帝乘轿）、乾隆御制《中和殿记》屏风</td></tr></tbody></table><p>中和殿是一座边长约24米的正方形建筑，四面开门，四面设窗，四面各设三交六椀菱花槅扇门。这种四面通透的形制在紫禁城的大殿中绝无仅有，既便于皇帝出入，也暗合&quot;四通八达、无往不中&quot;的寓意。</p><p>殿顶为<strong>单檐四角攒尖顶</strong>，上覆铜胎鎏金宝顶，在阳光下金光灿灿，是三大殿天际线上一个精巧的句读。殿内高悬&quot;允执厥中&quot;匾额，语出《尚书·大禹谟》，告诫帝王治国须持守中道。殿中放置两座皇帝赴典礼时乘坐的<strong>肩舆</strong>（御轿），以及一面刻有乾隆御制《中和殿记》的屏风。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="大典前的-静默时刻" tabindex="-1">大典前的&quot;静默时刻&quot; <a class="header-anchor" href="#大典前的-静默时刻" aria-label="Permalink to &quot;大典前的&quot;静默时刻&quot;&quot;">​</a></h3><p>每逢太和殿举行登基、册封、朝贺等大典礼，皇帝需先乘舆至中和殿暂驻。在这里，礼部官员会最后一次核对手续流程，皇帝稍事休息、整理仪容，待时辰一到，才起驾前往太和殿升座。这座小殿承担的是&quot;大典前最后一间准备室&quot;的功能——外面是万人山呼的太和殿广场，里面是片刻的宁静，一墙之隔，便是从&quot;人&quot;到&quot;天子&quot;的转换。</p><h3 id="阅视祝版与亲耕农具" tabindex="-1">阅视祝版与亲耕农具 <a class="header-anchor" href="#阅视祝版与亲耕农具" aria-label="Permalink to &quot;阅视祝版与亲耕农具&quot;">​</a></h3><p>中和殿还承担着两项颇具象征意义的礼仪：每逢皇帝赴天坛、地坛、太庙祭祀前，要在此<strong>阅视祝版</strong>（祭文），确认无误后方能举行大典，以示对天地祖宗的恭敬。每年春季皇帝行&quot;亲耕礼&quot;（在先农坛象征性扶犁耕田）之前，也要在中和殿<strong>检视种子与农具</strong>。堂堂天子在一座小殿里郑重其事地查看谷种和犁具——这套仪式的意义不在农事本身，而在于向天下昭示&quot;以农为本&quot;的治国姿态。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ul><li><strong>攒尖宝顶</strong>：从太和殿背后回望，鎏金宝顶是三大殿天际线上最亮眼的一笔，与太和殿的重檐庑殿顶形成大小对比。</li><li><strong>&quot;允执厥中&quot;匾额</strong>：殿内正中高悬，是理解中和殿命名哲学与帝王治国理念的钥匙。</li><li><strong>四面通透的形制</strong>：绕殿一周，欣赏四面相同的菱花槅扇门——这种&quot;四方如一&quot;的设计正是&quot;中&quot;的视觉化表达。</li><li><strong>肩舆与屏风</strong>：透过殿门可见两座御轿和乾隆御记屏风，是难得一见的清宫礼仪实物。</li></ul><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li><strong>别匆匆走过</strong>：中和殿夹在两座大殿之间，游客往往一掠而过。它恰恰是三大殿节奏中不可或缺的&quot;呼吸&quot;，值得驻足细看。</li><li><strong>最佳机位</strong>：站在太和殿与中和殿之间的月台上，可同时框住两座殿宇，大小对比一目了然。</li><li><strong>外观为主</strong>：与太和殿一样，中和殿内部不开放入内，只能隔门观赏。</li><li><strong>留意名字含义</strong>：把&quot;太和&quot;&quot;中和&quot;&quot;保和&quot;三个名字连起来读，正是《周易》&quot;保合太和，乃利贞&quot;的完整哲学——三大殿的命名是一套连贯的治国理念。</li></ul><hr><p><strong>📍 位置</strong>：外朝中轴线，太和殿与保和殿之间 <strong>⏱️ 建议游览</strong>：10-15分钟 <strong>🔗 上一站</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/taihe-dian.html">太和殿</a><strong>🔗 下一站</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/baohe-dian.html">保和殿</a><strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/">故宫博物院概览</a></p>',21)])])}const c=o(n,[["render",l]]);export{q as __pageData,c as default};
